fix:
private void handleBlockComment(Comment comment) {
  String value = comment.getValue();
  int firstAtIndex = value.indexOf("@");
  if (firstAtIndex == 0 || value.charAt(firstAtIndex - 1) == '\n') {
    errorReporter.warning(
        SUSPICIOUS_COMMENT_WARNING,
        sourceName,
        comment.getLineno(), "", 0);
  } else if (value.startsWith("/*!") && value.endsWith("*/")){
      return;
  }else if (value.startsWith("/") && firstAtIndex > 2 && value.contains("\n") ) {
    errorReporter.warning(
        INCONSISTENT_HANDLING_OF_NON_JSDOC_COMMENTS,
        sourceName,
        comment.getLineno(), "", 0);
  }
}

